PocketOption.swift:
## Swift Usage

```swift
import binaryoptionstoolsuni

func run() async throws {
    let ssid = "YOUR_SESSION_ID_HERE"
    let api = try await PocketOption.init(ssid: ssid)

    // Account info
    let balance = try await api.balance()
    print("Balance: \(balance)")
    print("Is demo: \(api.isDemo())")

    // Place a trade
    let deal = try await api.trade(asset: "EURUSD_otc", action: .call, time: 60, amount: 1.0)
    print("Profit: \(deal.profit)")

    // Convenience methods
    let buyDeal = try await api.buy(asset: "EURUSD_otc", time: 60, amount: 1.0)
    let sellDeal = try await api.sell(asset: "EURUSD_otc", time: 60, amount: 1.0)

    // Historical candles
    let candles = try await api.getCandles(asset: "EURUSD_otc", period: 60, offset: 0)
    for candle in candles {
        print("\(candle.timestamp): \(candle.open) -> \(candle.close)")
    }

    try await api.shutdown()
}
```

