PocketOption.go:
## Go Usage

```go
package main

import (
    "fmt"
    bot "github.com/ChipaDevTeam/BinaryOptionsTools-v2"
)

func main() {
    ssid := "YOUR_SESSION_ID_HERE"
    api, err := bot.PocketOptionInit(ssid)
    if err != nil {
        panic(err)
    }

    // Account info
    balance, _ := api.Balance()
    fmt.Printf("Balance: %f\n", balance)
    fmt.Printf("Is demo: %v\n", api.IsDemo())

    // Place a trade
    deal, err := api.Trade("EURUSD_otc", bot.ActionCall, 60, 1.0)
    if err != nil {
        panic(err)
    }
    fmt.Printf("Profit: %f\n", deal.Profit)

    // Historical candles
    candles, _ := api.GetCandles("EURUSD_otc", 60, 0)
    for _, candle := range candles {
        fmt.Printf("%d: %f -> %f\n", candle.Timestamp, candle.Open, candle.Close)
    }

    api.Shutdown()
}
```

PocketOption.javascript:
## JavaScript Usage

```javascript
import { PocketOption, Action } from 'binary-options-tools-uni';

async function main() {
    const ssid = 'YOUR_SESSION_ID_HERE';
    const api = await PocketOption.init(ssid);

    // Account info
    const balance = await api.balance();
    console.log(`Balance: ${balance}`);
    console.log(`Is demo: ${api.isDemo()}`);

    // Place a trade
    const deal = await api.trade('EURUSD_otc', Action.Call, 60, 1.0);
    console.log(`Profit: ${deal.profit}`);

    // Convenience methods
    const buyDeal = await api.buy('EURUSD_otc', 60, 1.0);
    const sellDeal = await api.sell('EURUSD_otc', 60, 1.0);

    // Historical candles
    const candles = await api.getCandles('EURUSD_otc', 60, 0);
    candles.forEach(c => console.log(`${c.timestamp}: ${c.open} -> ${c.close}`));

    await api.shutdown();
}

main();
```

